public static long[] solve(long[] nums, long[][] queries) {
    int n = nums.length;
    int m = queries.length;
    long[] ans = new long[m];

    for (int i = 0; i < m; i++) {
        long l = queries[i][0];
        long r = queries[i][1];
        long threshold = queries[i][2];
        long maxFreq = -1;
        long result = -1;
        long[] freq = new long[(int)1e9 + 1]; // Assuming nums[i] is up to 1e9

        for (int j = (int)l; j <= (int)r; j++) {
            long num = nums[j];
            freq[(int)num]++;
            if (freq[(int)num] >= threshold) {
                if (freq[(int)num] > maxFreq || (freq[(int)num] == maxFreq && num < result)) {
                    maxFreq = freq[(int)num];
                    result = num;
                }
            }
        }
        ans[i] = result;
    }

    return ans;
}
